  ('fire-eq-tech-moex-02020', 'fire-eq-tech', 'fire-eq-tech-moex-103-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '若欲登記設立消防安全設備檢修專業機構，依規定其實收資本額應在新臺幣 x 萬元以上，並置有專任之 消防設備師及消防設備士合計達y人以上，其中消防設備師至少z人。則x、y、z各為何？', '["x=800、y=8、z=2", "x=1000、y=10、z=2", "x=1200、y=10、z=2", "x=1200、y=12、z=3"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "0594b9c8adbf", "answer_pdf_sha1": "7fadfbf2acfc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "402", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
