  ('fire-eq-tech-moex-02029', 'fire-eq-tech', 'fire-eq-tech-moex-103-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，下列有關廚房選設滅火設備之規定何者錯誤？', '["廚房樓地板面積在200平方公尺以上者，得選設泡沫滅火設備", "廚房樓地板面積在200平方公尺以上者，得選設二氧化碳滅火設備", "廚房樓地板面積在200平方公尺以上者，得選設乾粉滅火設備", "樓地板面積在300平方公尺以上之餐廳，其廚房排油煙管及煙罩應設簡易自動滅火裝置"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "0594b9c8adbf", "answer_pdf_sha1": "7fadfbf2acfc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "402", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
